text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표 시점을 금요일 15:00 KST로 잡는다.",
        "condition": "smoke test가 통과해야 한다.",
        "source_certainty": "confirmed"
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다.",
        "condition": "스크립트 수정은 계약(contract) 자체가 잘못된 경우에만 검토한다.",
        "source_certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "result": "rejected",
        "source_certainty": "confirmed"
      },
      {
        "proposal": "수요일에 공개 릴리스한다.",
        "result": "not adopted; 최종 목표는 금요일 15:00 KST로 정리됨",
        "source_certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "status": "내부 스트레치 목표로만 언급됨",
        "source_certainty": "confirmed"
      },
      {
        "item": "README install steps를 목요일까지 검토",
        "status": "가능하면 진행하자는 수준으로 언급되었고, 담당자는 지정되지 않음",
        "source_certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있음",
        "source_certainty": "confirmed"
      },
      {
        "risk": "README install steps가 오래되면 release notes가 사용자에게 오해를 줄 수 있음",
        "source_certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?",
        "status": "미해결",
        "source_certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 적어야 하는가?",
        "status": "미결정",
        "source_certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "item": "고객명 또는 외부 파트너명은 언급되지 않음",
        "note": "인물 또는 대상은 추정하지 않음",
        "source_certainty": "confirmed"
      },
      {
        "item": "예산, 보안 사고, 프로덕션 장애, 법무 승인 요구사항은 언급되지 않음",
        "note": "존재한다고 해석하지 않음",
        "source_certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": "Minjun의 smoke 결과 게시 후",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README install steps를 검토한다.",
      "due": "목요일 if possible",
      "status": "unassigned / not confirmed as owned",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": "다음 확인 포인트는 1) Minjun의 smoke test 결과, 2) tarball path의 정확성, 3) README install steps의 최신성, 4) 최종 릴리스 승인자입니다. 기재되지 않은 고객명, 예산, 보안, 장애, 법무, 오너, 데드라인은 절대 보완 추정하지 마십시오. 수요일 릴리스는 내부 스트레치 목표로만 취급하고, 공개 릴리스 목표는 smoke 통과 시 금요일 15:00 KST로 유지합니다.",
  "non_invention_rules": [
    "고객명 또는 외부 파트너명을 만들지 않는다.",
    "예산, 보안 사고, 프로덕션 장애, 법무 승인 요구사항을 추가하지 않는다.",
    "owner가 없는 항목에 소유자를 임의 지정하지 않는다.",
    "명시되지 않은 deadline을 생성하지 않는다.",
    "smoke 결과, tarball path, release approval authority, release note 포함 여부를 추정으로 확정하지 않는다.",
    "fixture에 없는 사실은 공개-safe synthetic notes 밖에서 보강하지 않는다."
  ]
}
